// تحليل شامل للإدارة والتحليلات التجارية
const inputData = items[0].json;
const { action, adminId, data, timestamp } = inputData;

// تصنيف أنواع الأنشطة الإدارية
const adminActionTypes = {
  'admin_login': {
    category: 'security',
    riskLevel: 'medium',
    requiresLogging: true,
    alertThreshold: 5
  },
  'admin_action': {
    category: 'management',
    riskLevel: 'high',
    requiresLogging: true,
    alertThreshold: 1
  },
  'analytics_viewed': {
    category: 'monitoring',
    riskLevel: 'low',
    requiresLogging: true,
    alertThreshold: 50
  },
  'system_alert': {
    category: 'incident',
    riskLevel: 'critical',
    requiresLogging: true,
    alertThreshold: 1
  }
};

// الحصول على معلومات النشاط
const actionInfo = adminActionTypes[action] || {
  category: 'unknown',
  riskLevel: 'medium',
  requiresLogging: true,
  alertThreshold: 10
};

// تحليل المشرف
const adminAnalysis = {
  adminId,
  role: data?.role || 'admin',
  department: data?.department || 'general',
  accessLevel: data?.accessLevel || 'standard',
  loginMethod: data?.loginMethod || 'password',
  ipAddress: data?.ipAddress,
  userAgent: data?.userAgent,
  location: data?.location
};

// تحليل الأمان
const securityAnalysis = {
  isNewLocation: data?.isNewLocation || false,
  isNewDevice: data?.isNewDevice || false,
  suspiciousActivity: data?.multipleFailedAttempts || false,
  outsideBusinessHours: new Date(timestamp).getHours() < 8 || new Date(timestamp).getHours() > 18,
  isWeekend: [0, 6].includes(new Date(timestamp).getDay()),
  riskScore: 0
};

// حساب نقاط المخاطر
securityAnalysis.riskScore = 
  (securityAnalysis.isNewLocation ? 20 : 0) +
  (securityAnalysis.isNewDevice ? 30 : 0) +
  (securityAnalysis.suspiciousActivity ? 50 : 0) +
  (securityAnalysis.outsideBusinessHours ? 10 : 0) +
  (securityAnalysis.isWeekend ? 5 : 0);

// تحليل الإجراء المحدد
const actionAnalysis = {
  actionType: data?.actionType,
  targetResource: data?.targetResource,
  modifications: data?.modifications || [],
  affectedUsers: data?.affectedUsers || 0,
  dataModified: data?.dataModified || false,
  systemChanges: data?.systemChanges || false
};

// تحليل التأثير التجاري
const businessImpact = {
  severity: actionInfo.riskLevel,
  usersAffected: actionAnalysis.affectedUsers,
  systemsAffected: data?.systemsAffected || [],
  downtime: data?.downtime || 0,
  revenueImpact: actionAnalysis.affectedUsers > 100 ? 'high' : 
                actionAnalysis.affectedUsers > 10 ? 'medium' : 'low'
};

// تحليل النظام والأداء
const systemAnalysis = action === 'system_alert' ? {
  alertType: data?.alertType,
  severity: data?.severity || 'medium',
  component: data?.component,
  errorCode: data?.errorCode,
  errorMessage: data?.errorMessage,
  affectedFeatures: data?.affectedFeatures || [],
  autoResolution: data?.autoResolution || false
} : null;

// تحليل التحليلات المشاهدة
const analyticsAnalysis = action === 'analytics_viewed' ? {
  reportType: data?.reportType,
  dateRange: data?.dateRange,
  metrics: data?.metrics || [],
  exportFormat: data?.exportFormat,
  scheduledReport: data?.scheduled || false
} : null;

// تحديد التنبيهات المطلوبة
let alertsRequired = [];
if (securityAnalysis.riskScore > 50) {
  alertsRequired.push('high_risk_admin_activity');
}
if (actionInfo.riskLevel === 'critical') {
  alertsRequired.push('critical_system_event');
}
if (businessImpact.usersAffected > 100) {
  alertsRequired.push('high_impact_change');
}
if (securityAnalysis.isNewLocation && adminAnalysis.accessLevel === 'super_admin') {
  alertsRequired.push('super_admin_new_location');
}

// تحديد الإجراءات التلقائية
let automatedActions = [];
if (securityAnalysis.riskScore > 70) {
  automatedActions.push('require_additional_verification');
  automatedActions.push('log_detailed_session');
}
if (actionInfo.riskLevel === 'critical') {
  automatedActions.push('notify_all_admins');
  automatedActions.push('create_incident_ticket');
}
if (businessImpact.downtime > 0) {
  automatedActions.push('activate_incident_response');
}

// إنشاء تقرير الحدث
const eventReport = {
  eventId: `${action}_${adminId}_${Date.now()}`,
  summary: `${action} by ${adminAnalysis.role} ${adminId}`,
  details: {
    admin: adminAnalysis,
    security: securityAnalysis,
    action: actionAnalysis,
    business: businessImpact,
    system: systemAnalysis,
    analytics: analyticsAnalysis
  },
  classification: {
    severity: actionInfo.riskLevel,
    category: actionInfo.category,
    requiresReview: securityAnalysis.riskScore > 30 || actionInfo.riskLevel === 'critical'
  }
};

// تحليل الاتجاهات
const trendAnalysis = {
  timestamp: new Date(timestamp),
  hour: new Date(timestamp).getHours(),
  dayOfWeek: new Date(timestamp).getDay(),
  isBusinessHours: new Date(timestamp).getHours() >= 8 && new Date(timestamp).getHours() <= 18,
  patternType: securityAnalysis.outsideBusinessHours ? 'after_hours' : 'business_hours',
  frequency: 'single_event' // يمكن تطويرها لتتبع التكرار
};

// تحديد مستوى الاستجابة
const responseLevel = {
  priority: securityAnalysis.riskScore > 70 ? 'urgent' :
           actionInfo.riskLevel === 'critical' ? 'high' :
           securityAnalysis.riskScore > 30 ? 'medium' : 'low',
  timeframe: securityAnalysis.riskScore > 70 ? 'immediate' :
            actionInfo.riskLevel === 'critical' ? '15 minutes' :
            securityAnalysis.riskScore > 30 ? '1 hour' : '24 hours',
  escalation: securityAnalysis.riskScore > 90 || businessImpact.usersAffected > 500
};

return [{
  json: {
    adminId,
    action,
    actionInfo,
    adminAnalysis,
    securityAnalysis,
    actionAnalysis,
    businessImpact,
    systemAnalysis,
    analyticsAnalysis,
    alertsRequired,
    automatedActions,
    eventReport,
    trendAnalysis,
    responseLevel,
    processedAt: new Date().toISOString(),
    requiresImmediateAction: responseLevel.priority === 'urgent' || responseLevel.escalation
  }
}];
